const fs=require('fs');
const d=JSON.parse(fs.readFileSync('deep_scrape_merged_v2_2026-04-29T13-23-38_cleaned.json','utf8'));
const p0=d.customers.filter(r=>r.priority==='P0');
for(const r of p0) {
  console.log('=== CUSTOMER:', r.name, '|', r.tier, '|', r.countryCode, '| msgs='+r.messages.length, '===');
  // sort messages by timestamp
  const msgs = r.messages.sort((a,b) => (a.timestamp||'').localeCompare(b.timestamp||''));
  for(const m of msgs) {
    console.log((m.side==='received'?'[客]':'[我]'), m.timestamp, m.content ? m.content.substring(0,300) : '(empty)');
  }
  console.log('');
}"

