const fs = require('fs');
const { Document, Packer, Paragraph, TextRun, HeadingLevel, Table, TableRow, TableCell, WidthType, BorderStyle, AlignmentType, ShadingType, PageBreak } = require('docx');

// ==== ANALYSIS DATA ====

const customers = [
  // ===== BATCH 1: CRITICAL/HIGH =====
  {
    name: 'yoselyn Rodriguez',
    tier: 'S',
    country: 'US',
    lang: '西班牙语',
    stage: '7→8（已发货，严重延迟）',
    priority: '🔴 紧急',
    messages: 19,
    summary: '客户3月初下单并付款，已等待近2个月。我们反复说"等待船卸货"，客户从耐心等待变成明显不满。4/30最新消息仍是"aun no"（还没到）。此客户存在服务失败风险。',
    stageDetail: '阶段7（已发货，运输中）。但货物延迟远超正常周期——从3月中旬发货至今近50天，"等待船卸货"理由已无法继续使用。',
    blockage: '物流严重延迟。我们未提供真实的物流追踪信息和具体到货时间。客户已从"gracias"变成"aun no llega"——耐心耗尽信号明显。核心问题：我们不知道货在哪。',
    nextStep: '1）立即查询实际物流状态和真实预计到达时间；2）给客户一个诚实的更新+具体日期，不再用"等待船卸货"；3）如已丢件或严重超期，考虑补发/退款方案。',
    script: {
      text: 'Yoselyn，我理解你的担心——等待的时间已经远超正常。我刚查了最新状态：[XX物流实际状态]，预计[XX日期]到达你那边。如果到[XX日期]还没收到，我会立即安排补发。在此期间如有任何问题，随时找我。抱歉让你等这么久。',
      translateTo: '西班牙语'
    },
    hook: null,
    postNote: '⚠️ 此客户需立即处理。物流状态需查询后填入[XX]。如无法查到物流，直接给客户两个选择：退款或重新发货。信任修复优先于成本控制。'
  },
  {
    name: 'Karl brown',
    tier: 'S',
    country: 'US',
    lang: '英语',
    stage: '3→4（已报价待回复→谈判中）',
    priority: '🔴 高',
    messages: 4,
    summary: '美国专业买家，发出极其详细的定制布尿裤询盘——有logo文件、7项明确需求、问了MOQ/价格/打样/交期。我们回复了部分问题但不完整，承诺"通过邮件发送"后27天无互动。高价值客户面临流失。',
    stageDetail: '阶段3→4。客户发出专业级询盘（4/3），我们给了部分回答，后说"已发邮件"。客户从未回复。静默27天。',
    blockage: '①信息缺口：客户问了7个问题，我们实质上只回答了2-3个。②渠道断裂："已发邮件"打断了聊天内的沟通流。③MOQ不一致风险：客户询100pcs，但定制业务规则是500pcs起订。④无价格信息：我们未给出任何价格区间。',
    nextStep: '在聊天内（非邮件）补全7个问题的答案。承认延迟。给出实际价格区间。区分定制MOQ（500pcs）和试用订单（100pcs可商量）。用帮宝适奥运背书重建信任。',
    script: {
      text: 'Karl，抱歉我之前的回复没有完整回答你的所有问题。以下是你要的全部信息，都在这里：

①面料：精梳棉（触感高级）或超细纤维（快干），两种都适合布尿裤
②定制logo满版印花：可以做，数码热升华印刷，你的AI/PNG文件直接能用
③闭合方式：推荐按扣（更耐用），魔术贴也可选
④尺码：新生儿到幼儿全尺码，我可以发标准尺码表给你
⑤包装定制：可选logo塑料袋、品牌纸盒或吊牌，告诉我你的偏好
⑥MOQ：全定制500件起，但建议先做100件试单测试市场
⑦参考价：100件约$3.20-3.80/件，500件约$2.70-3.20/件 [内部标注：最终报价须老板确认]
⑧打样：3-7天，样品费在批量订单中抵扣
⑨交期：确认设计后25-35天

去年帮宝适奥运联名礼盒里的吸汗巾就是我们这条产线做的——同样的品控标准。要我先发尺码表和类似定制布尿裤的实拍图给你看吗？',
      translateTo: '英语'
    },
    hook: 'hook_pampers_olympic ✅（话术末尾嵌入）',
    postNote: '⚠️ 内部注意：定制MOQ实际为500件/款/色/码。若客户坚持100件，需单独和老板确认是否接受。本话术中"100件试单"为引导性表达，最终MOQ须老板确认。'
  },
  // ===== BATCH 2: HIGH =====
  {
    name: 'Abdou Salam Kane',
    tier: 'S',
    country: 'SN (塞内加尔)',
    lang: '法语',
    stage: '8→9（已签收→长线维护）',
    priority: '🟡 中高',
    messages: 11,
    summary: '塞内加尔老客户，已完成至少一单布尿裤插片。4月4日主动说"hello"——明确的重联信号——但我们回复是推新品+模糊产品描述，没有问他为什么找我们。静默26天。',
    stageDetail: '阶段8→9。历史订单已完成。客户主动发起重联（4/4 "hello"），说明他有需求/问题/补货需求。我们未捕捉到这个信号。',
    blockage: '非传统卡点。问题是机会错失——客户给了窗口，我们没接住。',
    nextStep: '重新联系，承认可能误解了他的来意。直接问"上次你说hello是想和我聊什么？"。提供补货或新需求的帮助。塞内加尔法语区，关系维护很重要。',
    script: {
      text: 'Bonjour Abdou Salam！我重新看了我们的对话——上次你说"hello"的时候，我可能太快跳到了产品介绍，没有先问你需要什么。你当时是想补货、问之前订单的问题、还是有新需求要聊？我在这里，你说。',
      translateTo: '法语'
    },
    hook: null,
    postNote: '💬情感：可在后续对话中询问塞内加尔市场近况，建立个人连接。'
  },
  {
    name: 'Dania Sanchez',
    tier: 'S',
    country: 'MX (墨西哥)',
    lang: '西班牙语',
    stage: '7→8（已发货→应已签收）',
    priority: '🟡 中高',
    messages: 12,
    summary: '墨西哥Sinaloa客户，极小订单（$3.96/2件）。3月12日发货（运单ALS01458702612），预计10-25个工作日到达。至今48天无跟进。订单应已到达。需查询物流。',
    stageDetail: '阶段7→8。已发货预计已签收，但未确认。因Sinaloa地区曾因安全问题存在物流延迟风险。',
    blockage: '物流到达确认缺失。超过48天未跟进——可能是客户已收到货物但没有告知，也可能是物流出了问题。',
    nextStep: '查询ALS01458702612运单号最新状态。如已签收→温和收集反馈。如未签收→调查原因，提供方案。注意：此订单金额极低($3.96)，等级S与实际订单价值不匹配。',
    script: {
      text: 'Hola Dania！Quería dar seguimiento a tu pedido. Según el número de guía ALS01458702612 — ¿ya lo recibiste? Si ya llegó, ¿qué te parecieron los productos? Si no ha llegado aún, dime y lo reviso de inmediato.',
      translateTo: '西班牙语'
    },
    hook: null,
    postNote: '物流跟踪结果：[XX]。如果已签收且客户满意，可推更多品类。如果物流丢失，优先补发或退款——$3.96不值得破坏客户关系。'
  },
  {
    name: 'fatmt mtr',
    tier: 'S',
    country: 'IQ (伊拉克)',
    lang: '英语',
    stage: '4（谈判中——样品阶段）',
    priority: '🟡 中高',
    messages: 12,
    summary: '伊拉克客户，要10件冬季珊瑚绒连体衣（0-12月），指定了褐/蓝/白/灰四色，明确说"yes please show me the samples"。我们确认褐/白/粉有现货样品，蓝/灰待确认。静默9天。',
    stageDetail: '阶段4。讨论样品和颜色。客户主动要求看样品——这是明确的购买信号。',
    blockage: '蓝/灰颜色确认未完成。客户可能在等待全部颜色确认后再决定。另：伊拉克物流需要确认。',
    nextStep: '跟进蓝/灰颜色结果。发送现货颜色样品实拍。确认伊拉克发货方式（通常通过迪拜中转或客户自有货代）。',
    script: {
      text: 'Quick update: Blue is confirmed available. Grey still needs 2-3 days for final check. For the 3 ready colors (brown, white, pink), I can send you sample photos right now so you can see the fabric quality immediately — want me to send them here? Also, for Iraq delivery — do you have a freight forwarder in China or Dubai?',
      translateTo: '英语'
    },
    hook: 'hook_pampers_olympic ✅（如客户对品质存疑时使用）',
    postNote: '样品实拍需准备：褐/白/粉三色珊瑚绒连体衣细节图。如有工厂已有图片可直接使用。'
  },
  // ===== BATCH 3: MEDIUM =====
  {
    name: 'syf khdr',
    tier: 'S',
    country: 'US（发叙利亚）',
    lang: '阿拉伯语',
    stage: '3（已报价，待回复）',
    priority: '🟡 中',
    messages: 16,
    summary: '叙利亚相关买家（可能居美），问50件女童夏装套装价格+能否发叙利亚。我们报价$3.95/件+运费$445 DAP。运费远超货值（$197.50 vs $445）。静默13天。',
    stageDetail: '阶段3。我们已报价，客户未回复。',
    blockage: '运费是核心卡点——$445运费几乎是货值的2.3倍。叙利亚目的地可能涉及制裁合规问题，需确认是否能发货。',
    nextStep: '1）确认叙利亚发货合规性[XX]。2）如可发，询问客户是否有中国货代可自提（非洲/中东客户的常见做法）。3）如不可发，诚实告知并询问备选地址。',
    script: {
      text: '我重新查了运费——快递到叙利亚确实偏高。很多中东客户的做法是用自己的中国货代从我们工厂提货，运费能省很多。你有中国货代吗？如果没有，我可以帮你问问有没有发叙利亚的合作物流。另外确认一下：叙利亚那边清关没问题吧？',
      translateTo: '阿拉伯语'
    },
    hook: null,
    postNote: '⚠️叙利亚制裁：发前必须确认合规。不确定则标注[XX待确认]。'
  },
  {
    name: 'BuyLi Now',
    tier: 'S',
    country: 'LY (利比亚→肯尼亚)',
    lang: '英语',
    stage: '3（已报价，待回复）',
    priority: '🟡 中',
    messages: 7,
    summary: '利比亚/肯尼亚客户。发产品卡后我们回复报价（300件/$3.95+运费$165到蒙巴萨），但回复用了印尼语——非客户语言。客户说"mombasa kenya"是英文，我们回印尼文。静默11天。',
    stageDetail: '阶段3。报价已发，但存在语言错误。',
    blockage: '①回复语言错误（印尼语vs英语/斯瓦希里语）降低了专业形象。②报价基于未确认的300件假设。③利比亚→肯尼亚跨国物流复杂。',
    nextStep: '用英语重新联系，承认语言错误，确认数量和物流细节。蒙巴萨是东非大港——可推海运方案降低成本。',
    script: {
      text: "Hello! I apologize — my last message went out in the wrong language. Let me restart. You mentioned Mombasa, Kenya as your delivery address. Is that your final destination, or will goods be forwarded to Libya from there? Also, I quoted based on 300 pieces — is that the right quantity for you? Let me know and I'll recalculate the best option for shipping to Mombasa.",
      translateTo: '英语'
    },
    hook: null,
    postNote: '蒙巴萨海运方案查询：[XX]。如果客户目标量确实100-500件，海运CIF Mombasa会比快递便宜很多。'
  },
  {
    name: 'Peggy Hamungala',
    tier: 'S',
    country: 'ZM (赞比亚)',
    lang: '英语',
    stage: '3→4（已报价→谈判中）',
    priority: '🟡 中',
    messages: 20,
    summary: '赞比亚客户，要5件产品。我们报了$4.20/件+$66运费=$92总价。客户要求人民币报价（暗示有中国渠道），我们转为591.5元。客户说"shipping to Ghana"但国家标记ZM。静默8天。',
    stageDetail: '阶段3→4。报价已发（含人民币转换），客户在考虑。',
    blockage: '①运费占比高——$66运费 vs $21货值。②客户要人民币报价→可能在中国有货代/朋友，可引导客户自提。③"发加纳"与国家标记ZM矛盾，需确认实际目的地。',
    nextStep: '确认实际目的地。建议客户使用中国货代自提降低成本。提示可增加1-2件均摊运费。',
    script: {
      text: "Hi! Just following up — did the RMB quote help? One tip: if the shipping cost feels high for 5 pieces, adding 2-3 more pieces barely changes the shipping weight, so your per-piece total comes down. Also — do you have a freight forwarder in China? If you do, they can pick up from us and arrange their own shipping, which is usually cheaper. By the way, I noticed you mentioned Ghana — is that the final destination, or Zambia? Just want to make sure I quote the right route.",
      translateTo: '英语'
    },
    hook: null,
    postNote: '目的地矛盾（ZM vs Ghana）需客户确认。如需寄加纳，运费可能不同。'
  },
  {
    name: 'martin wamundila',
    tier: 'S',
    country: 'ZM (赞比亚→科特迪瓦)',
    lang: '法语',
    stage: '4（谈判中——"我考虑一下"）',
    priority: '🟡 中',
    messages: 17,
    summary: '赞比亚/科特迪瓦法语客户。问了2件套价格后明确提出"要独特的、不要大众款""关注质量和质感"。我们推荐了多款+提了定制方案，他说"merci je vais réfléchir"。之后发了劳动节问候+新品。静默20天。',
    stageDetail: '阶段4。客户说"我考虑一下"——这是决策困难信号，不是拒绝。',
    blockage: '决策困难——客户想要独特但有太多选择。我们推荐了5款产品+定制选项，增加了决策负担。他需要的是帮他缩小选择，而非更多选项。',
    nextStep: '不要推更多产品。帮他缩小到1-2个方向：选基础款+独家面料=独特产品。展示几个西非畅销面料。科特迪瓦法语市场注重差异化。',
    script: {
      text: 'Bonjour Martin！我一直在想你说的"想要独特的"——我有个更好的方法。与其从目录里选现成款式，不如这样：你从我们这里挑一个基础版型，我帮你搭2-3个西非那边没见过的面料花型——我们有300多种现货面料，出来的效果是真正的独家款，而不是大路货。要不要我发几张我们在西非市场走得好的面料图给你看看？你选一个方向，我先出个效果图。',
      translateTo: '法语'
    },
    hook: 'hook_fabric_library ⚠️（皱皱纱花型PDF可用，缺可视化对比图——使用替代："我发几张面料图给你看"）',
    postNote: '西非畅销面料选择：[XX需确认]。可发3-5张皱皱纱花型图，让客户二选一。'
  },
  // ===== BATCH 4: LOW/THIN DATA =====
  {
    name: 'Talosh talosh',
    tier: 'A',
    country: 'IL (以色列)',
    lang: '英语',
    stage: '1（初次接触）',
    priority: '🟢 低',
    messages: 4,
    summary: '以色列客户，仅发了一张产品卡+一个希伯来字母"מ"（疑似误触）。我们的希伯来语自动回复未获回应。无实质互动。',
    stageDetail: '阶段1。客户发卡浏览。无具体问题。',
    blockage: null,
    nextStep: '用英语（非希伯来语）轻量重新激活。以色列商务沟通以英语为主，机器翻译的希伯来语可能适得其反。',
    script: {
      text: "Hi! We're the factory that produced the Pampers 2024 Olympic gift box baby towels — specializing in OEM/ODM baby and kids clothing. Are you looking at toddler sets for your store, or browsing for a specific category?",
      translateTo: '英语'
    },
    hook: null,
