// ==== HELPERS ====
function headerCell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    shading: { type: ShadingType.SOLID, color: '1a5276' },
    children: [new Paragraph({ children: [new TextRun({ text, bold: true, color: 'FFFFFF', size: 20, font: 'Microsoft YaHei' })], spacing: { before: 40, after: 40 } })],
  });
}

function cell(text, width) {
  return new TableCell({
    width: { size: width, type: WidthType.PERCENTAGE },
    children: [new Paragraph({ children: [new TextRun({ text, size: 19, font: 'Microsoft YaHei' })], spacing: { before: 30, after: 30 } })],
  });
}

function heading(text, level) {
  return new Paragraph({ heading: level, children: [new TextRun({ text, bold: true, font: 'Microsoft YaHei', size: level === HeadingLevel.HEADING_1 ? 32 : level === HeadingLevel.HEADING_2 ? 28 : 24 })], spacing: { before: 200, after: 100 } });
}

function para(text, opts = {}) {
  return new Paragraph({
    children: [new TextRun({ text, size: 21, font: 'Microsoft YaHei', ...opts })],
    spacing: { before: 60, after: 60 }
  });
}

